{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This reaction is a classic textbook example of the Ritter reaction, demonstrating the formation of a stable tert-butyl carbocation from tert-butanol under strong acid (H2SO4) conditions. This carbocation is then trapped by acetonitrile, the simplest common nitrile, to form a nitrilium ion intermediate, which upon hydrolysis yields N-tert-butylacetamide. All reactants and the product are simple, acyclic, and lack complex functional groups, making this a clear and unambiguous representation of the core transformation.",
    "collision_avoidance_note": "The use of simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) avoids motifs common in other named reactions. Specifically, it avoids arenes (Friedel-Crafts, etc.), complex ring systems (Beckmann, Schmidt rearrangements), and other reactive functional groups that could cause collisions with unrelated reaction families. The transformation is a clear C-N bond formation to create an amide from a nitrile and a carbocation source, which is the defining feature of the Ritter reaction."
  }
}
